# Mock API call demonstrating low-latency online lookup
class OnlineFeatureServer:
    def __init__(self, redis_client):
        self.redis = redis_client

    def get_online_features(self, entity_keys, feature_names):
        # Batch lookup keys using pipeline to minimize network round-trips
        pipe = self.redis.pipeline()
        for key in entity_keys:
            # Fetch hash values representing the features
            pipe.hmget(f"features:{key}", feature_names)
        results = pipe.execute()
        return dict(zip(entity_keys, results))
